// Flatten the extraction result into a row-friendly format
// Nested objects/arrays are converted to JSON strings for spreadsheet compatibility
const data = $input.first().json;
const result = data.result || {};
const output = {};

for (const [key, value] of Object.entries(result)) {
  if (Array.isArray(value)) {
    output[key] = JSON.stringify(value);
  } else if (typeof value === 'object' && value !== null) {
    output[key] = JSON.stringify(value);
  } else {
    output[key] = value;
  }
}

return [{ json: output }];
